import{_ as e,o as a,c as s,ae as t}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Unity","description":"","frontmatter":{"title":"Unity","slug":"unity"},"headers":[],"relativePath":"developer-hub/unity.md","filePath":"developer-hub/unity.md"}'),i={name:"developer-hub/unity.md"};function o(r,n,l,p,c,d){return a(),s("div",null,[...n[0]||(n[0]=[t(`<div class="info custom-block"><p class="custom-block-title">Note</p><p>In order to give <strong>iOS 14</strong> developers full control over the user experience, the Branch SDK will not trigger the IDFA permission modal.</p><p>However, we will still collect and use IDFAs when available if you do choose to trigger the modal.</p><p><a href="https://help.branch.io/faq/docs/sdk-faqs" target="_blank" rel="noreferrer">Learn more</a></p></div><div class="warning custom-block"><p class="custom-block-title">Warning</p><p>If you reference <strong>Google Play Services version 17 or higher</strong>, you <strong>must</strong> complete Google&#39;s update instructions <a href="https://developers.google.com/android/guides/releases#june_17_2019" target="_blank" rel="noreferrer">here</a>.</p><p>Due to a major Google Play Services change made in June 2019, not completing the update steps will cause Branch&#39;s Android SDK (and various other cross-platform SDKs, e.g. Unity) to stop collecting Android AID which we use to ensure accurate deep linking and attribution.</p><p>If you are running Google Play Services versions below 17, no update is necessary.</p><p>To use Google Play Services <strong>versions below 17 for future app builds</strong>, follow these <a href="./unity.html#workaround-implementation-steps-for-using-google-play-services-version-17">workaround implementation steps</a>.</p></div><div class="warning custom-block"><p class="custom-block-title">Warning</p><p>If you use your own Android Manifest and not the one provided with the Branch SDK, make sure you change the <code>android:name</code> field of your launcher activity you are referencing from <code>com.unity3d.player.UnityPlayerActivity</code> to <code>BranchUnityActivity</code>. <code>BranchUnityActivity</code> extends the <code>UnityPlayerActivity</code> but also contains code responsible for initializing the Branch SDK on Android.</p><p>Not doing so will result in the callback in <code>init()</code> never getting hit.</p></div><h2 id="configure-branch" tabindex="-1">Configure Branch <a class="header-anchor" href="#configure-branch" aria-label="Permalink to &quot;Configure Branch&quot;">​</a></h2><ol><li><p>Configure Branch:</p><ul><li><strong>New Branch</strong>: In the left-hand navigation, go to <strong>Configuration</strong> and click on <strong>Link Controls</strong>. Navigate to the <strong>Link Routing Rules</strong> tab to configure your app settings.</li><li><strong>Legacy Branch</strong>: Navigate to the <a href="https://dashboard.branch.io/settings/link" target="_blank" rel="noreferrer">Link Settings page</a>.</li></ul></li><li><p>Customize your app.link domain:</p></li></ol><h2 id="configure-the-branch-sdk" tabindex="-1">Configure the Branch SDK <a class="header-anchor" href="#configure-the-branch-sdk" aria-label="Permalink to &quot;Configure the Branch SDK&quot;">​</a></h2><ul><li><a href="https://github.com/BranchMetrics/unity-branch-deep-linking-attribution/raw/master/BranchUnityWrapper.unitypackage" target="_blank" rel="noreferrer">Download the latest SDK version</a> or clone our <a href="https://github.com/BranchMetrics/unity-branch-deep-linking" target="_blank" rel="noreferrer">open-source GitHub repository</a>.</li><li>Import the 1BranchUnityWrapper.unitypackage1 into your project by clicking <code>Assets -&gt; Import Package</code>.</li></ul><h2 id="configure-app" tabindex="-1">Configure app <a class="header-anchor" href="#configure-app" aria-label="Permalink to &quot;Configure app&quot;">​</a></h2><p>You can configure your Unity app to work with Branch by either using a Branch prefab asset or by adding a <code>branch.json</code> file.</p><div class="danger custom-block"><p class="custom-block-title">Warning</p><p>Please ensure that the <strong>Activity</strong> checkbox is checked in <strong>Project Settings</strong> → <strong>Player,</strong> because the Unity SDK currently uses <code>UnityPlayerActivity</code>.</p><p>Not doing so <strong>will</strong> <strong>cause a build error</strong> on Android.</p></div><h3 id="configure-with-branch-prefab" tabindex="-1">Configure with Branch prefab <a class="header-anchor" href="#configure-with-branch-prefab" aria-label="Permalink to &quot;Configure with Branch prefab&quot;">​</a></h3><p>Add the Branch prefab asset to the <strong>first scene</strong> of your Unity project.</p><div class="info custom-block"><p class="custom-block-title">Note</p><ul><li>Do not forget to click on the <strong>Apply Changes</strong> once you are done.</li><li>On Android, these values are used to generate <code>Assets/Plugins/Android/AndroidManifest.xml</code>. If you have any conflicts, you may manually enter these settings.</li><li>On iOS, these values are used to update the <code>Info.plist</code>, <code>branch_domains.entitlements</code> and update a few build settings to enable C++ exceptions. If you have any conflicts, you may manually enter these settings.</li></ul></div><h4 id="prefab-fields" tabindex="-1">Prefab fields <a class="header-anchor" href="#prefab-fields" aria-label="Permalink to &quot;Prefab fields&quot;">​</a></h4><p>To find your Branch keys, URI schemes, and link domains:</p><ul><li><strong>New Branch</strong>: In the left-hand navigation, go to <strong>Configuration</strong> and click on <strong>Security &amp; Access</strong> for your Branch keys and link domains. Click on <strong>Link Controls</strong> and navigate to the <strong>Link Routing Rules</strong> tab for URI schemes and platform-specific settings.</li><li><strong>Legacy Branch</strong>: Navigate to the <a href="https://dashboard.branch.io/account-settings/app" target="_blank" rel="noreferrer">App Settings page</a> for your Branch keys, or the <a href="https://dashboard.branch.io/link-settings" target="_blank" rel="noreferrer">Link Settings page</a> for URI schemes, link domains, and platform-specific settings.</li></ul><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Enable Logging</strong></td><td>This feature is currently NOT working. Workaround is to set this in the <code>branch.json</code> config file.</td></tr><tr><td><strong>Test Mode</strong></td><td>This feature is currently NOT working on iOS. Workaround is to set this in the <code>branch.json</code> config file. Enables use of the Test Key.</td></tr><tr><td><strong>Live Branch Key</strong></td><td>This is the Live Branch key found in Branch (see navigation above).</td></tr><tr><td><strong>Live Branch URI</strong></td><td>This is the Live URI scheme that you have set for your app in Branch (see navigation above).</td></tr><tr><td><strong>Live Android Path Prefix</strong></td><td>This field is only applicable if you are on the <code>bnc.lt</code> domain. You can find it underneath the field labeled SHA256 Cert Fingerprints once you&#39;ve enabled App Links. It will look something like this: <code>/WSuf</code> (the initial / character should be included).</td></tr><tr><td><strong>Live App Links</strong></td><td>This field is applicable if you want to enable <code>APPLINKS</code> and <code>UNIVERSAL LINKS</code> for your domain. Please make sure to add the correct domain found in Branch (see navigation above). Add the -alternate domain to have your Branch links deeplink from your <a href="./deepviews.html">Deepviews</a> and <a href="./journeys-overview.html">Journeys</a>. If you are not using a <code>app.links</code> domain please contact our <a href="./submit-a-ticket.html">support team</a>.</td></tr><tr><td><strong>Test Branch Key</strong></td><td>This is the test Branch key found in Branch (see navigation above).</td></tr><tr><td><strong>Test Branch URI</strong></td><td>This is the test URI scheme that you have set for your app in Branch (see navigation above).</td></tr><tr><td><strong>Test Android Path Prefix</strong></td><td>This field is only applicable if you are on the <code>bnc.lt</code> domain of your Test Branch app. You can find it underneath the field labeled SHA256 Cert Fingerprints once you&#39;ve enabled App Links. It will look something like this: <code>/WSuf</code> (the initial / character should be included).</td></tr><tr><td><strong>Test App Links</strong></td><td>This field is applicable if you want to enable <code>APPLINKS</code> and <code>UNIVERSAL LINKS</code> for your domain. Please make sure to add the correct domain found in Branch (see navigation above). Add the -alternate domain to have your Branch links deeplink from your <a href="./deepviews.html">Deepviews</a> and <a href="./journeys-overview.html">Journeys</a>. If you are not using a <code>app.links</code> domain please contact our <a href="./submit-a-ticket.html">support team</a></td></tr></tbody></table><h3 id="configuration-with-branch-json" tabindex="-1">Configuration with <code>branch.json</code> <a class="header-anchor" href="#configuration-with-branch-json" aria-label="Permalink to &quot;Configuration with \`branch.json\`&quot;">​</a></h3><p>You may also configure the app by adding <code>Assets/StreamingAssets/branch.json</code> to your project.</p><table tabindex="0"><thead><tr><th>Key</th><th>Type</th><th></th></tr></thead><tbody><tr><td>enableLogging</td><td>boolean</td><td>Enables Branch SDK logging</td></tr><tr><td>deferInitForPluginRuntime</td><td>boolean</td><td>Defers underlying iOS and Android SDKs initialization until the C# layer registers a callback.</td></tr><tr><td>useTestInstance</td><td>boolean</td><td>Enables using the Test Key on iOS</td></tr></tbody></table><h2 id="initialize-branch" tabindex="-1">Initialize Branch <a class="header-anchor" href="#initialize-branch" aria-label="Permalink to &quot;Initialize Branch&quot;">​</a></h2><p>Add Branch to your <code>Monobehavior</code> script of your <strong>first Scene:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>using UnityEngine;</span></span>
<span class="line"><span>        using System.Collections;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        public class Spin : MonoBehaviour {</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        // Use this for initialization</span></span>
<span class="line"><span>        void Start () {</span></span>
<span class="line"><span>        Branch.initSession(CallbackWithBranchUniversalObject);</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        void CallbackWithBranchUniversalObject(BranchUniversalObject buo,</span></span>
<span class="line"><span>        BranchLinkProperties linkProps,</span></span>
<span class="line"><span>        string error) {</span></span>
<span class="line"><span>        if (error != null) {</span></span>
<span class="line"><span>        Debug.LogError(&quot;Error : &quot;</span></span>
<span class="line"><span>        + error);</span></span>
<span class="line"><span>        } else if (linkProps.controlParams.Count &gt; 0) {</span></span>
<span class="line"><span>        Debug.Log(&quot;Deeplink params : &quot;</span></span>
<span class="line"><span>        + buo.ToJsonString()</span></span>
<span class="line"><span>        + linkProps.ToJsonString());</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        // Update is called once per frame</span></span>
<span class="line"><span>        void Update () {</span></span>
<span class="line"><span>        //rotate 90 degress per second</span></span>
<span class="line"><span>        transform.Rotate(Vector3.up * Time.deltaTime*90);</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>        }</span></span></code></pre></div><h2 id="test-branch-deep-link" tabindex="-1">Test Branch Deep Link <a class="header-anchor" href="#test-branch-deep-link" aria-label="Permalink to &quot;Test Branch Deep Link&quot;">​</a></h2><ol><li><a href="https://dashboard.branch.io/quick-links/qlc/define" target="_blank" rel="noreferrer">Create a Branch Short Link</a> in Branch.</li><li>Delete your app from the device.</li><li>Paste Short Link in <strong>Google Hangouts (Android)</strong> or <strong>Notes (iOS).</strong></li><li>Click on the Short Link to open your app.</li><li>Compile and download your app to your device.</li><li>You should see deferred deep link data show in your app.</li></ol><h2 id="implement-features" tabindex="-1">Implement features <a class="header-anchor" href="#implement-features" aria-label="Permalink to &quot;Implement features&quot;">​</a></h2><h3 id="create-content-reference" tabindex="-1">Create content reference <a class="header-anchor" href="#create-content-reference" aria-label="Permalink to &quot;Create content reference&quot;">​</a></h3><p>The <strong>Branch Universal Object</strong> encapsulates the thing you want to share with your link:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>BranchUniversalObject universalObject = new BranchUniversalObject();</span></span>
<span class="line"><span>        // Content index mode: 0 - private mode, 1 - public mode</span></span>
<span class="line"><span>        universalObject.contentIndexMode = 1;</span></span>
<span class="line"><span>        //Identifier that helps Branch dedupe across many instances of the same content.</span></span>
<span class="line"><span>        universalObject.canonicalIdentifier = &quot;id12345&quot;;</span></span>
<span class="line"><span>        // OG title</span></span>
<span class="line"><span>        universalObject.title = &quot;id12345 title&quot;;</span></span>
<span class="line"><span>        // OG Description</span></span>
<span class="line"><span>        universalObject.contentDescription = &quot;My awesome piece of content!&quot;;</span></span>
<span class="line"><span>        // OG Image</span></span>
<span class="line"><span>        universalObject.imageUrl = &quot;https://example.com/image.png&quot;;</span></span>
<span class="line"><span>        // User defined key value pair</span></span>
<span class="line"><span>        universalObject.metadata.AddCustomMetadata(&quot;foo&quot;, &quot;bar&quot;);</span></span></code></pre></div><h3 id="create-deep-link" tabindex="-1">Create Deep Link <a class="header-anchor" href="#create-deep-link" aria-label="Permalink to &quot;Create Deep Link&quot;">​</a></h3><p>After you have created a <code>Branch Universal Object</code>, Define Link Properties:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>BranchLinkProperties linkProperties = new BranchLinkProperties();</span></span>
<span class="line"><span>        linkProperties.tags.Add(&quot;tag1&quot;);</span></span>
<span class="line"><span>        linkProperties.tags.Add(&quot;tag2&quot;);</span></span>
<span class="line"><span>        // Feature link is associated with. Eg. Sharing</span></span>
<span class="line"><span>        linkProperties.feature = &quot;invite&quot;;</span></span>
<span class="line"><span>        // The channel where you plan on sharing the link Eg.Facebook, Twitter, SMS etc</span></span>
<span class="line"><span>        linkProperties.channel = &quot;Twitter&quot;;</span></span>
<span class="line"><span>        linkProperties.stage = &quot;2&quot;;</span></span>
<span class="line"><span>        // Parameters used to control Link behavior</span></span>
<span class="line"><span>        linkProperties.controlParams.Add(&quot;$desktop_url&quot;, &quot;http://example.com&quot;);</span></span></code></pre></div><p>Then, generate a Branch link:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Branch.getShortURL(universalObject, linkProperties, (parameters, error) =&gt; {</span></span>
<span class="line"><span>        if (error != null) {</span></span>
<span class="line"><span>        Debug.LogError(&quot;Branch.getShortURL failed: &quot; + error);</span></span>
<span class="line"><span>        } else if (params != parameters) {</span></span>
<span class="line"><span>        Debug.Log(&quot;Branch.getShortURL shared params: &quot; + parameters[&quot;url&quot;].ToString());</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>        });</span></span></code></pre></div><h3 id="share-deep-link" tabindex="-1">Share Deep Link <a class="header-anchor" href="#share-deep-link" aria-label="Permalink to &quot;Share Deep Link&quot;">​</a></h3><p>Share Branch Deep Links between users and apps:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Branch.shareLink(universalObject, linkProperties, &quot;Sharing link: &quot;, (parameters, error) =&gt; {</span></span>
<span class="line"><span>        if (error != null) {</span></span>
<span class="line"><span>        Debug.LogError(&quot;Branch.shareLink failed: &quot; + error);</span></span>
<span class="line"><span>        } else if (parameters != null) {</span></span>
<span class="line"><span>        Debug.Log(&quot;Branch.shareLink: &quot; + parameters[&quot;sharedLink&quot;].ToString() + &quot; &quot; + parameters[&quot;sharedChannel&quot;].ToString());</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>        });</span></span></code></pre></div><h3 id="read-deep-link" tabindex="-1">Read Deep Link <a class="header-anchor" href="#read-deep-link" aria-label="Permalink to &quot;Read Deep Link&quot;">​</a></h3><ul><li>Read Deep Link params from a <strong>BUO</strong> in your <code>BranchInitSession callback</code></li><li>Returns <a href="./creating-a-deep-link.html#section-read-deep-links">deep link properties</a></li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>public void CallbackWithBranchUniversalObject(BranchUniversalObject universalObject, BranchLinkProperties linkProperties, string error) {</span></span>
<span class="line"><span>        if (error != null) {</span></span>
<span class="line"><span>        Debug.LogError(&quot;Branch Error: &quot; + error);</span></span>
<span class="line"><span>        } else {</span></span>
<span class="line"><span>        Debug.Log(&quot;Branch initialization completed: &quot;);</span></span>
<span class="line"><span>        Debug.Log(&quot;Universal Object: &quot; + universalObject.ToJsonString());</span></span>
<span class="line"><span>        Debug.Log(&quot;Link Properties: &quot; + linkProperties.ToJsonString());</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>        }</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">Note</p><p>This refereshes with every session (App Installs and App Opens).</p></div><h4 id="retrieve-link-data" tabindex="-1">Retrieve link data <a class="header-anchor" href="#retrieve-link-data" aria-label="Permalink to &quot;Retrieve link data&quot;">​</a></h4><div class="warning custom-block"><p class="custom-block-title">Warning</p><p>Make sure you run this code after <code>initSession()</code>.</p></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>//get the latest referring params (last Branch link click)</span></span>
<span class="line"><span>        BranchUniversalObject obj = Branch.getLatestReferringBranchUniversalObject();</span></span>
<span class="line"><span>        BranchLinkProperties link = Branch.getLatestReferringBranchLinkProperties();</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        //get the first referring params (open or install)</span></span>
<span class="line"><span>        BranchUniversalObject obj = Branch.getFirstReferringBranchUniversalObject();</span></span>
<span class="line"><span>        BranchLinkProperties link = Branch.getFirstReferringBranchLinkProperties();</span></span></code></pre></div><h4 id="nativelinktm-deferred-deep-linking-ios-only" tabindex="-1">NativeLink™ Deferred Deep Linking (iOS only) <a class="header-anchor" href="#nativelinktm-deferred-deep-linking-ios-only" aria-label="Permalink to &quot;NativeLink™ Deferred Deep Linking (iOS only)&quot;">​</a></h4><p>Use iOS pasteboard to enable deferred deep linking using Branch NativeLink™.</p><p>To use this feature you must:</p><ul><li><p><a href="./configure-default-link-behaviors.html">Enable NativeLink™ Deep Linking</a>:</p><ul><li><strong>New Branch</strong>: In the left-hand navigation, go to <strong>Configuration</strong> and click on <strong>Link Controls</strong>. Navigate to the <strong>Link Routing Rules</strong> tab, then find the <strong>Mobile Routing</strong> section and find <strong>iOS</strong>.</li><li><strong>Legacy Branch</strong>: Navigate to the <a href="https://dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer">Configuration page</a>.</li></ul><p><strong>or</strong></p></li><li><p>Manually configure your Branch Link to use <a href="./creating-a-deep-link.html#deep-linking">$ios_nativelink</a>.</p></li></ul><div class="warning custom-block"><p class="custom-block-title">Warning</p><p>Make sure the underlying <strong>iOS SDK Version is v1.39.4+.</strong></p></div><p>Implement one of the <a href="./ios-advanced-features.html">pasteboard opt-in options</a> in the native iOS SDK code.</p><h4 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to &quot;Access&quot;">​</a></h4><p>Please note that deferred deep linking requires a premium plan. Please <a href="https://www.branch.io/contact-sales/" target="_blank" rel="noreferrer">contact our Sales team</a> to learn more about pricing and availability.</p><h3 id="navigate-to-and-display-content" tabindex="-1">Navigate to and display content <a class="header-anchor" href="#navigate-to-and-display-content" aria-label="Permalink to &quot;Navigate to and display content&quot;">​</a></h3><p>Use the link parameters to decide which view you wish to load:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>public class MyCoolBehaviorScript : MonoBehaviour {</span></span>
<span class="line"><span>        void Start () {</span></span>
<span class="line"><span>        Branch.initSession(delegate(Dictionary&lt;string, object&gt; parameters, string error) {</span></span>
<span class="line"><span>        if (parameters.ContainsKey(&quot;picture_id&quot;) {</span></span>
<span class="line"><span>        // load the Scene to show the picture</span></span>
<span class="line"><span>        SceneManager.LoadSceneAsync(&quot;ImageScene&quot;, LoadSceneMode.Additive);</span></span>
<span class="line"><span>        } else {</span></span>
<span class="line"><span>        // load your normal Scene</span></span>
<span class="line"><span>        SceneManager.LoadSceneAsync(&quot;NormalScene&quot;, LoadSceneMode.Single);</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>        });</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>        }</span></span></code></pre></div><h3 id="track-content" tabindex="-1">Track content <a class="header-anchor" href="#track-content" aria-label="Permalink to &quot;Track content&quot;">​</a></h3><p>If you want to track the number of times a user views a piece of content associated with a Branch Universal Object, use the following snippet:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Branch.registerView(universalObject);</span></span></code></pre></div><h3 id="track-users" tabindex="-1">Track users <a class="header-anchor" href="#track-users" aria-label="Permalink to &quot;Track users&quot;">​</a></h3><h4 id="set-user-ids-on-login" tabindex="-1">Set user IDs on login <a class="header-anchor" href="#set-user-ids-on-login" aria-label="Permalink to &quot;Set user IDs on login&quot;">​</a></h4><p>Set the identity of a user (ID, UUID, etc) for events, deep links, and referrals:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Branch.setIdentity(&quot;your user id&quot;);</span></span></code></pre></div><h4 id="unset-user-ids-on-logout" tabindex="-1">Unset user IDs on logout <a class="header-anchor" href="#unset-user-ids-on-logout" aria-label="Permalink to &quot;Unset user IDs on logout&quot;">​</a></h4><p>To log a user out, use the <code>logout()</code> method:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Branch.logout();</span></span></code></pre></div><h3 id="tracking-user-actions-and-events" tabindex="-1">Tracking user actions and events <a class="header-anchor" href="#tracking-user-actions-and-events" aria-label="Permalink to &quot;Tracking user actions and events&quot;">​</a></h3><p>Use the <code>BranchEvent</code> class to monitor unique user interactions beyond app installations and openings. Use it to log Branch Events like adding items to a shopping cart or completing a registration form. The class links content via a <code>BranchUniversalObject</code> and allow for metric analytics on the Branch Dashboard. <code>BranchEventType</code> will enumerate frequently tracked events and parameters. You can also use custom names and custom parameters using a <a href="./track-branch-events.html">Branch Custom Event.</a></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>BranchEvent e01 = new BranchEvent (BranchEventType.COMPLETE_REGISTRATION);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        e01.SetAffiliation(&quot;my_affilation&quot;);</span></span>
<span class="line"><span>        e01.SetCoupon(&quot;my_coupon&quot;);</span></span>
<span class="line"><span>        e01.SetCurrency(BranchCurrencyType.USD);</span></span>
<span class="line"><span>        e01.SetTax(10.0f);</span></span>
<span class="line"><span>        e01.SetRevenue(100.0f);</span></span>
<span class="line"><span>        e01.SetShipping(1000.0f);</span></span>
<span class="line"><span>        e01.SetDescription(&quot;my_description&quot;);</span></span>
<span class="line"><span>        e01.SetSearchQuery(&quot;my_search_query&quot;);</span></span>
<span class="line"><span>        e01.AddCustomData(&quot;custom_data_key01&quot;, &quot;custom_data_value01&quot;);</span></span>
<span class="line"><span>        e01.AddContentItem(universalObject);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        Branch.sendEvent (e01);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        BranchEvent e02 = new BranchEvent (&quot;MY_CUSTOM_EVENT&quot;);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        e02.SetAffiliation(&quot;my_affilation&quot;);</span></span>
<span class="line"><span>        e02.SetCoupon(&quot;my_coupon&quot;);</span></span>
<span class="line"><span>        e02.SetCurrency(BranchCurrencyType.USD);</span></span>
<span class="line"><span>        e02.SetTax(10.0f);</span></span>
<span class="line"><span>        e02.SetRevenue(100.0f);</span></span>
<span class="line"><span>        e02.SetShipping(1000.0f);</span></span>
<span class="line"><span>        e02.SetDescription(&quot;my_description&quot;);</span></span>
<span class="line"><span>        e02.SetSearchQuery(&quot;my_search_query&quot;);</span></span>
<span class="line"><span>        e02.AddCustomData(&quot;custom_data_key01&quot;, &quot;custom_data_value01&quot;);</span></span>
<span class="line"><span>        e02.AddContentItem(universalObject);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        Branch.sendEvent (e02);</span></span></code></pre></div><h2 id="troubleshooting-issues" tabindex="-1">Troubleshooting issues <a class="header-anchor" href="#troubleshooting-issues" aria-label="Permalink to &quot;Troubleshooting issues&quot;">​</a></h2><h2 id="ios-unity-4-6" tabindex="-1">iOS + Unity 4.6 <a class="header-anchor" href="#ios-unity-4-6" aria-label="Permalink to &quot;iOS + Unity 4.6&quot;">​</a></h2><p>Branch requires ARC, and we don’t intend to add checks throughout the SDK to try and support pre-ARC.<br> However, you can add flags to the project to compile the Branch files with ARC. If you wish to do this<br> add <code>-fobjectivec-arc</code> to all Branch files.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>By default this flag is checked, but please check before building for iOS.</p></div><h2 id="android-using-your-own-custom-application-class" tabindex="-1">Android - using your own custom application class <a class="header-anchor" href="#android-using-your-own-custom-application-class" aria-label="Permalink to &quot;Android - using your own custom application class&quot;">​</a></h2><p>If you are using your own custom <code>application</code> class, you will need to add Branch android library into your project and call the following in method <code>OnCreate()</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Branch.getAutoInstance(this.getApplicationContext());</span></span></code></pre></div><p>If you are using your own custom <code>activity</code> class, please make sure that you are overriding the following functions:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@Override</span></span>
<span class="line"><span>        public void onCreate(Bundle savedInstanceState) {</span></span>
<span class="line"><span>        super.onCreate(savedInstanceState);</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        @Override</span></span>
<span class="line"><span>        public void onNewIntent(Intent intent) {</span></span>
<span class="line"><span>        this.setIntent(intent);</span></span>
<span class="line"><span>        }</span></span></code></pre></div><h2 id="support-branch-with-different-plugins" tabindex="-1">Support Branch with different plugins <a class="header-anchor" href="#support-branch-with-different-plugins" aria-label="Permalink to &quot;Support Branch with different plugins&quot;">​</a></h2><p>The Branch SDK has its own custom <code>activity</code> and <code>application</code> classes. Other plugins that use their own<br> custom activity and application classes can cause conflicts between these classes.</p><p>To resolve these conflicts:</p><ol><li>Create a empty android library.</li><li>Add the Branch plugin along with the other plugins into your project.</li><li>Create a custom <code>activity</code> and <code>application</code> class that will contain the custom logic for all your plugins.</li><li>Build your library.</li><li>Add your library into your Unity project.</li><li>Change <code>android:name</code> to name of your custom <code>application</code> class in the <code>application</code> tag of your Manifest.</li><li>Change <code>android:name</code> to name of your custom <code>activity</code> class in the <code>activity</code> tag of your Manifest.</li></ol><h2 id="support-several-impl-app-controller-subclass" tabindex="-1">Support several <code>IMPL_APP_CONTROLLER_SUBCLASS</code> <a class="header-anchor" href="#support-several-impl-app-controller-subclass" aria-label="Permalink to &quot;Support several \`IMPL_APP_CONTROLLER_SUBCLASS\`&quot;">​</a></h2><p>The Branch Unity SDK plugin uses its own <code>UnityAppController</code> that expands default <code>AppController.</code> This is used to catch Universal Links.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@interface BranchAppController : UnityAppController</span></span>
<span class="line"><span>        {</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>        @end</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        @implementation BranchAppController</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        - (BOOL)application:(UIApplication *)application continueUserActivity:(NSUserActivity *)userActivity restorationHandler:(void (^)(NSArray *))restorationHandler {</span></span>
<span class="line"><span>        BOOL handledByBranch = [[BranchUnityWrapper sharedInstance] continueUserActivity:userActivity];</span></span>
<span class="line"><span>        return handledByBranch;</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        @end</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        IMPL_APP_CONTROLLER_SUBCLASS(BranchAppController)</span></span></code></pre></div><p>Some plugins expand the default <code>AppController</code> the same was as Branch does, like the Cardboard SDK plugin. To resolve conflicts:</p><ol><li>Merge all custom <code>AppControllers</code> in one.</li><li>Comment code in other <code>AppControllers</code> (or delete other <code>AppControllers</code>).</li></ol><h2 id="sample-app" tabindex="-1">Sample app <a class="header-anchor" href="#sample-app" aria-label="Permalink to &quot;Sample app&quot;">​</a></h2><p><a href="https://github.com/BranchMetrics/unity-branch-deep-linking/tree/master/BranchUnityTestBed" target="_blank" rel="noreferrer">Branch testbed app</a></p><h2 id="workaround-implementation-steps-for-using-google-play-services-version-17" tabindex="-1">Workaround implementation steps for using Google Play Services &lt; Version 17 <a class="header-anchor" href="#workaround-implementation-steps-for-using-google-play-services-version-17" aria-label="Permalink to &quot;Workaround implementation steps for using Google Play Services &lt; Version 17&quot;">​</a></h2><ol><li>Install <code>BranchUnityWrapper.unitypackage</code>.</li><li>Delete <code>android-support-customtabs-23.3.0.jar</code> from <strong>Assets-&gt;Plugins-&gt;Branch-&gt;Android-&gt;libs</strong>.</li><li>Create a <strong>Assets-&gt;Plugins-&gt;Branch-&gt;Editor</strong> folder.</li><li>Add the attached <code>BranchPluginDependencies.xml</code> to the new <strong>Editor</strong> folder.</li><li>Install the latest Google Play Resolver from <a href="https://github.com/googlesamples/unity-jar-resolver" target="_blank" rel="noreferrer">https://github.com/googlesamples/unity-jar-resolver</a>.</li><li>Dependencies will now auto-resolve, but you may want to confirm by listing the libraries from the play resolver menu. You will see the following block:</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dependencies {implementation &#39;com.android.installreferrer:installreferrer:1.0&#39; // Assets/Plugins/Editor/BranchPluginDependencies.xml:11implementation &#39;com.android.support:customtabs:23.3.0&#39; // Assets/Plugins/Editor/BranchPluginDependencies.xml:13implementation &#39;com.google.android.gms:play-services-ads:16.0.0&#39; // Assets/Plugins/Editor/BranchPluginDependencies.xml:12}</span></span></code></pre></div>`,91)])])}const g=e(i,[["render",o]]);export{u as __pageData,g as default};
